class Solution {
    public boolean canPartitionKSubsets(int[] nums, int k) {
        int sum = 0;
        for (int num : nums) {
            sum += num;
        }
        if (sum % k != 0) {
            return false;
        }
        int targetSum = sum / k;
        boolean[] used = new boolean[nums.length];
        return backtrack(nums, used, 0, 0, k, targetSum);
    }
    private boolean backtrack(int[] nums, boolean[] used, int start, int currentSum, int k, int targetSum) {
        if (k == 0) {
            return true;
        }
        if (currentSum == targetSum) {
            return backtrack(nums, used, 0, 0, k - 1, targetSum);
        }
        for (int i = start; i < nums.length; i++) {
            if (!used[i] && currentSum + nums[i] <= targetSum) {
                used[i] = true;
                if (backtrack(nums, used, i + 1, currentSum + nums[i], k, targetSum)) {
                    return true;
                }
                used[i] = false;
            }
        }
        return false;
    }
}
